import { useState } from "react";
import axios from "axios";

const API = "http://localhost:5000/api";

export default function App() {
  const [page, setPage] = useState("login");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [token, setToken] = useState("");
  const [query, setQuery] = useState("");
  const [suggestion, setSuggestion] = useState("");
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");

  const register = async () => {
    try {
      const res = await axios.post(`${API}/auth/register`, { name, email, password });
      setMessage(res.data.message);
      setPage("login");
    } catch (err) {
      setMessage(err.response?.data?.message || "Error");
    }
  };

  const login = async () => {
    try {
      const res = await axios.post(`${API}/auth/login`, { email, password });
      setToken(res.data.token);
      setPage("home");
    } catch (err) {
      setMessage(err.response?.data?.message || "Error");
    }
  };

  const getSuggestion = async () => {
    setLoading(true);
    try {
      const res = await axios.post(`${API}/suggest`,
        { query },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setSuggestion(res.data.suggestion);
    } catch (err) {
      setMessage("Error getting suggestion");
    }
    setLoading(false);
  };

  const getHistory = async () => {
    try {
      const res = await axios.get(`${API}/suggest/history`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setHistory(res.data);
      setPage("history");
    } catch (err) {
      setMessage("Error fetching history");
    }
  };

  const styles = {
    container: { maxWidth: "600px", margin: "40px auto", padding: "20px", fontFamily: "Arial" },
    input: { width: "100%", padding: "10px", marginBottom: "10px", borderRadius: "6px", border: "1px solid #ddd", fontSize: "16px" },
    button: { padding: "10px 20px", background: "#ff6b35", color: "white", border: "none", borderRadius: "6px", cursor: "pointer", marginRight: "10px", fontSize: "16px" },
    card: { background: "#f9f9f9", padding: "15px", borderRadius: "8px", marginBottom: "10px", border: "1px solid #eee" },
  };

  if (page === "register") return (
    <div style={styles.container}>
      <h2>🍱 Register — AI Food Suggester</h2>
      {message && <p style={{ color: "red" }}>{message}</p>}
      <input style={styles.input} placeholder="Name" value={name} onChange={e => setName(e.target.value)} />
      <input style={styles.input} placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} />
      <input style={styles.input} placeholder="Password" type="password" value={password} onChange={e => setPassword(e.target.value)} />
      <button style={styles.button} onClick={register}>Register</button>
      <button style={{ ...styles.button, background: "#666" }} onClick={() => setPage("login")}>Back to Login</button>
    </div>
  );

  if (page === "login") return (
    <div style={styles.container}>
      <h1>🍱 AI Food Suggester</h1>
      <h2>Login</h2>
      {message && <p style={{ color: "red" }}>{message}</p>}
      <input style={styles.input} placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} />
      <input style={styles.input} placeholder="Password" type="password" value={password} onChange={e => setPassword(e.target.value)} />
      <button style={styles.button} onClick={login}>Login</button>
      <button style={{ ...styles.button, background: "#666" }} onClick={() => setPage("register")}>Register</button>
    </div>
  );

  if (page === "history") return (
    <div style={styles.container}>
      <h2>📋 My Suggestion History</h2>
      <button style={styles.button} onClick={() => setPage("home")}>Back</button>
      <div style={{ marginTop: "20px" }}>
        {history.length === 0 && <p>No history yet!</p>}
        {history.map((item, i) => (
          <div key={i} style={styles.card}>
            <p><b>You asked:</b> {item.query}</p>
            <p><b>AI suggested:</b> {item.suggestion}</p>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div style={styles.container}>
      <h1>🍱 AI Food Suggester</h1>
      <p>Tell me what you're craving or what ingredients you have!</p>
      <input
        style={styles.input}
        placeholder="e.g. I have tomato, onion, rice... or I want something spicy!"
        value={query}
        onChange={e => setQuery(e.target.value)}
      />
      <button style={styles.button} onClick={getSuggestion} disabled={loading}>
        {loading ? "Thinking..." : "🤖 Get AI Suggestion"}
      </button>
      <button style={{ ...styles.button, background: "#666" }} onClick={getHistory}>
        📋 My History
      </button>
      <button style={{ ...styles.button, background: "#999" }} onClick={() => { setToken(""); setPage("login"); }}>
        Logout
      </button>

      {suggestion && (
        <div style={{ ...styles.card, marginTop: "20px", background: "#fff8f0", border: "1px solid #ff6b35" }}>
          <h3>🤖 AI Suggestion:</h3>
          <p>{suggestion}</p>
        </div>
      )}
    </div>
  );
}
